form:Form.form:Scripts:
	function valida (myThis)
{    
	if (Ctrl('f_ingreso').GetXValue() != "")
	{
		if (Ctrl('f_egreso').GetXValue() != "")
		{
			if (Ctrl('f_ingreso').GetXValue() > Ctrl('f_egreso').GetXValue())
			{
			  myThis.SetError('La Fecha de Ingreso debe ser anterior a la Fecha de Egreso');
				return false;
			}
		return true;				                          			
		}
	return true;
	}		
	else		
	{
	if (Ctrl('f_egreso').GetXValue() != "")
		{
			myThis.SetError('La Fecha de Ingreso debe ser anterior a la Fecha de Egreso');
			return false;
	  }
	return true;				                          			
	} 			     
return true;
}
